#include<bits/stdc++.h>
using namespace std;

char a[10005];

int main()
{
	int len;
	fgets(a,10005,stdin);
	len=strlen(a);
	//a[len-1]='\0';
	//len=len-1;
	for(int i=0;i<=len-1;i++)
	{
		if(a[i]=='A')
		{
			printf("Z");
		}
		else if(a[i]=='a')
		{
			printf("z");
		}
		else
		{
			if(a[i]>='b'&&a[i]<='z'||a[i]>='B'&&a[i]<='Z')
			{
				printf("%c",a[i]-1);
			}
			else
			{
				printf("%c",a[i]);
			}
		}
	}
	return 0;
}
